+
+#[test]
+fn all_packages_have_side_effects_false() {
+    for pkg in PACKAGES {
+        let v = read_pkg_json(pkg);
+        assert_eq!(
+            v["sideEffects"], false,
+            "{pkg} must have sideEffects: false for tree-shaking"
+        );
